SELECT ?teamLabel ?date
WHERE {
  ?series wdt:P31 wd:Q114240;
          wdt:P585 ?date;
          wdt:P1198 ?team.
  ?team rdfs:label ?teamLabel.
  FILTER (LANG(?teamLabel) = "en")
